external_knowledge:
- 'weathered the storm of the growing population' implies a population over 1 million;
- 'demographic balance' refers to the sex ratio (males per 100 females);
- 'energy creation prowess' refers to energy production;
- 'anticipated lifespan at birth' refers to life expectancy;
- 'individual health investment' refers to health expenditure per capita.

- "places" refers to countries;
- "how many people lived there in 2017" refers to population in thousands;
- "what portion of the population could read and write" refers to the literacy rate for 2017;
- "what fraction of the people lived in cities in that same year" refers to the urban population percentage in 2017.

sql:
SELECT AVG(population_2017) AS average_population_2017_under_60_literacy
FROM country_stats
WHERE literacy_rate_2017 < 60;

SELECT AVG(health_expenditure_per_capita_2017) AS average_health_expenditure
FROM health
WHERE life_expectancy_2017 > 75;

SELECT c.country_name, s.literacy_rate_2017, e.unemployment_rate_2017
FROM countries AS c
JOIN country_stats AS s ON c.country_id = s.country_id
JOIN economy AS e ON c.country_id = e.country_id
WHERE s.literacy_rate_2017 > (
    SELECT AVG(literacy_rate_2017) FROM country_stats
) AND e.unemployment_rate_2017 < (
    SELECT AVG(unemployment_rate_2017) FROM economy
);

